package com.synexis.management_service.security;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpMethod;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityCustomizer;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.annotation.web.configurers.HeadersConfigurer;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.config.Customizer;

/**
 * Spring Security setup for the API: which URLs are anonymous, CSRF policy, and
 * the password hashing bean used when
 * saving users.
 *
 * <p>
 * How it works: {@link #securityFilterChain(HttpSecurity)} disables CSRF
 * (typical for stateless JSON APIs) and
 * allows unauthenticated access to {@code /ping}, paths under
 * {@code /register/}, the H2 console, and {@code OPTIONS}
 * preflight; everything else requires an authenticated principal.
 * {@link #passwordEncoder()} is used by {@link
 * com.synexis.management_service.service.impl.AuthServiceImpl AuthService} for
 * encoding and verification.
 */
@Configuration
@EnableWebSecurity
@EnableMethodSecurity
public class SecurityConfig {

        /**
         * Omite por completo el filtro de seguridad en estas rutas (evita 403 cuando
         * {@code permitAll} no coincide con el
         * {@code RequestMatcher} de MVC en algunos entornos). Los métodos del
         * controlador no influyen en la URL: solo
         * importan las rutas declaradas en {@code @PostMapping} / {@code @GetMapping}.
         */
        @Bean
        public WebSecurityCustomizer webSecurityCustomizer() {
                return web -> web.ignoring()
                                .requestMatchers(
                                                "/ping",
                                                "/api/auth/**",
                                                "/api/clients/register",
                                                "/api/partners/register");
        }

        @Bean
        public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
                http.csrf(AbstractHttpConfigurer::disable)
                                .headers(headers -> headers.frameOptions(HeadersConfigurer.FrameOptionsConfig::disable))
                                .authorizeHttpRequests(
                                                auth -> auth
                                                                .requestMatchers(HttpMethod.OPTIONS, "/**").permitAll()
                                                                .requestMatchers(
                                                                                "/ping",
                                                                                "/api/auth/**",
                                                                                "/api/clients/register",
                                                                                "/api/partners/register")
                                                                .permitAll()
                                                                .anyRequest().authenticated())
                                .oauth2ResourceServer(oauth2 -> oauth2
                                                .jwt(Customizer.withDefaults()));
                return http.build();
        }

        /**
         * BCrypt strength default (10). Used to hash passwords before storing
         * {@code password_hash} in the database.
         */
        @Bean
        public PasswordEncoder passwordEncoder() {
                return new BCryptPasswordEncoder();
        }
}

package com.synexis.management_service.security;

import java.util.Collection;
import java.util.Collections;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpMethod;
import org.springframework.core.convert.converter.Converter;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityCustomizer;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.annotation.web.configurers.HeadersConfigurer;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.oauth2.jwt.Jwt;
import org.springframework.security.oauth2.server.resource.authentication.JwtAuthenticationConverter;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.config.Customizer;

/**
 * Spring Security setup for the API: which URLs are anonymous, CSRF policy, and
 * the password hashing bean used when
 * saving users.
 *
 * <p>
 * How it works: {@link #securityFilterChain(HttpSecurity)} disables CSRF
 * (typical for stateless JSON APIs) and
 * allows unauthenticated access to {@code /ping}, paths under
 * {@code /register/}, the H2 console, and {@code OPTIONS}
 * preflight; everything else requires an authenticated principal.
 * {@link #passwordEncoder()} is used by {@link
 * com.synexis.management_service.service.impl.AuthServiceImpl AuthService} for
 * encoding and verification.
 */
@Configuration
@EnableWebSecurity
@EnableMethodSecurity
public class SecurityConfig {

        /**
         * Omite por completo el filtro de seguridad en estas rutas (evita 403 cuando
         * {@code permitAll} no coincide con el
         * {@code RequestMatcher} de MVC en algunos entornos). Los métodos del
         * controlador no influyen en la URL: solo
         * importan las rutas declaradas en {@code @PostMapping} / {@code @GetMapping}.
         */
        @Bean
        public WebSecurityCustomizer webSecurityCustomizer() {
                return web -> web.ignoring()
                                .requestMatchers(
                                                "/ping",
                                                "/api/auth/**",
                                                "/api/clients/register",
                                                "/api/partners/register");
        }

        @Bean
        public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
                http.csrf(AbstractHttpConfigurer::disable)
                                .headers(headers -> headers.frameOptions(HeadersConfigurer.FrameOptionsConfig::disable))
                                .authorizeHttpRequests(
                                                auth -> auth
                                                                .requestMatchers(HttpMethod.OPTIONS, "/**").permitAll()
                                                                .requestMatchers(
                                                                                "/ping",
                                                                                "/api/auth/**",
                                                                                "/api/clients/register",
                                                                                "/api/partners/register")
                                                                .permitAll()
                                                                .anyRequest().authenticated())
                                .oauth2ResourceServer(oauth2 -> oauth2
                                                .jwt(jwt -> jwt.jwtAuthenticationConverter(jwtAuthenticationConverter())));
                return http.build();
        }

        /**
         * Maps Keycloak client roles from resource_access.telepresence.roles to ROLE_*
         * authorities so @PreAuthorize("hasRole('CLIENT')") works as expected.
         */
        @Bean
        public JwtAuthenticationConverter jwtAuthenticationConverter() {
                JwtAuthenticationConverter converter = new JwtAuthenticationConverter();
                converter.setJwtGrantedAuthoritiesConverter(new KeycloakClientRolesConverter("telepresence"));
                return converter;
        }

        static class KeycloakClientRolesConverter implements Converter<Jwt, Collection<GrantedAuthority>> {
                private final String clientId;

                KeycloakClientRolesConverter(String clientId) {
                        this.clientId = clientId;
                }

                @Override
                public Collection<GrantedAuthority> convert(Jwt jwt) {
                        Object resourceAccessObj = jwt.getClaims().get("resource_access");
                        if (!(resourceAccessObj instanceof Map<?, ?> resourceAccess)) {
                                return Collections.emptyList();
                        }

                        Object clientObj = resourceAccess.get(clientId);
                        if (!(clientObj instanceof Map<?, ?> clientMap)) {
                                return Collections.emptyList();
                        }

                        Object rolesObj = clientMap.get("roles");
                        if (!(rolesObj instanceof List<?> roles)) {
                                return Collections.emptyList();
                        }

                        return roles.stream()
                                        .filter(String.class::isInstance)
                                        .map(String.class::cast)
                                        .map(String::toUpperCase)
                                        .map(role -> "ROLE_" + role)
                                        .map(SimpleGrantedAuthority::new)
                                        .collect(Collectors.toSet());
                }
        }

        /**
         * BCrypt strength default (10). Used to hash passwords before storing
         * {@code password_hash} in the database.
         */
        @Bean
        public PasswordEncoder passwordEncoder() {
                return new BCryptPasswordEncoder();
        }
}

package com.synexis.management_service.service;

import com.synexis.management_service.dto.response.LoginResponse;

public interface LoginService {

    LoginResponse loginClient(String email, String password);

    LoginResponse loginPartner(String email, String password);
}

package com.synexis.management_service.service.impl;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.synexis.management_service.dto.response.LoginResponse;
import com.synexis.management_service.entity.Client;
import com.synexis.management_service.entity.Partner;
import com.synexis.management_service.exception.InvalidCredentialsException;
import com.synexis.management_service.exception.KeycloakUserCreationException;
import com.synexis.management_service.exception.WrongPasswordException;
import com.synexis.management_service.repository.ClientRepository;
import com.synexis.management_service.repository.PartnerRepository;
import com.synexis.management_service.service.LoginService;
import java.io.IOException;
import java.net.URI;
import java.net.URLEncoder;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.nio.charset.StandardCharsets;
import org.springframework.stereotype.Service;

@Service
public class LoginServiceImpl implements LoginService {

    private static final String KEYCLOAK_URL = "http://localhost:8085";
    private static final String REALM = "synexis";
    private static final String CLIENT_ID = "telepresence";
    private static final String CLIENT_SECRET = "wO8qciPyigPvlYPQAX3wzft18wa1lqv6";

    private final ClientRepository clientRepository;
    private final PartnerRepository partnerRepository;
    private final ObjectMapper objectMapper = new ObjectMapper();
    private final HttpClient httpClient = HttpClient.newHttpClient();

    public LoginServiceImpl(
            ClientRepository clientRepository,
            PartnerRepository partnerRepository) {
        this.clientRepository = clientRepository;
        this.partnerRepository = partnerRepository;
    }

    @Override
    public LoginResponse loginClient(String email, String password) {
        String normalizedEmail = email.trim().toLowerCase();
        Client client = clientRepository.findByEmailIgnoreCase(normalizedEmail)
                .orElseThrow(InvalidCredentialsException::new);

        TokenResult token = requestToken(normalizedEmail, password);
        return new LoginResponse(
                token.accessToken,
                token.refreshToken,
                token.tokenType,
                token.expiresIn,
                client.getId(),
                client.getEmail(),
                client.getName(),
                client.getRole().name());
    }

    @Override
    public LoginResponse loginPartner(String email, String password) {
        String normalizedEmail = email.trim().toLowerCase();
        Partner partner = partnerRepository.findByEmailIgnoreCase(normalizedEmail)
                .orElseThrow(InvalidCredentialsException::new);

        TokenResult token = requestToken(normalizedEmail, password);
        return new LoginResponse(
                token.accessToken,
                token.refreshToken,
                token.tokenType,
                token.expiresIn,
                partner.getId(),
                partner.getEmail(),
                partner.getName(),
                partner.getRole().name());
    }

    private TokenResult requestToken(String email, String password) {
        String formBody = "client_id=" + encode(CLIENT_ID)
                + "&client_secret=" + encode(CLIENT_SECRET)
                + "&grant_type=password"
                + "&username=" + encode(email)
                + "&password=" + encode(password);

        HttpRequest request = HttpRequest.newBuilder()
                .uri(URI.create(KEYCLOAK_URL + "/realms/" + REALM + "/protocol/openid-connect/token"))
                .header("Content-Type", "application/x-www-form-urlencoded")
                .POST(HttpRequest.BodyPublishers.ofString(formBody))
                .build();

        try {
            HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());
            if (response.statusCode() == 200) {
                JsonNode node = objectMapper.readTree(response.body());
                return new TokenResult(
                        node.path("access_token").asText(),
                        node.path("refresh_token").asText(),
                        node.path("token_type").asText(),
                        node.path("expires_in").asLong());
            }
            if (response.statusCode() == 400 || response.statusCode() == 401) {
                throw new WrongPasswordException();
            }
            throw new KeycloakUserCreationException(
                    "Error de autenticacion en Keycloak. Status: " + response.statusCode());
        } catch (InterruptedException ex) {
            Thread.currentThread().interrupt();
            throw new KeycloakUserCreationException("No se pudo validar el login con Keycloak: " + ex.getMessage());
        } catch (IOException ex) {
            throw new KeycloakUserCreationException("No se pudo validar el login con Keycloak: " + ex.getMessage());
        }
    }

    private String encode(String value) {
        return URLEncoder.encode(value, StandardCharsets.UTF_8);
    }

    private static final class TokenResult {
        private final String accessToken;
        private final String refreshToken;
        private final String tokenType;
        private final long expiresIn;

        private TokenResult(String accessToken, String refreshToken, String tokenType, long expiresIn) {
            this.accessToken = accessToken;
            this.refreshToken = refreshToken;
            this.tokenType = tokenType;
            this.expiresIn = expiresIn;
        }
    }
}

